    self.assertOptimizesTo(
        [
            migrations.CreateModel("Foo", [("name", models.CharField(max_length=255))]),
            migrations.AlterModelTable("Foo", "woohoo"),
            alter_foo,
            migrations.DeleteModel("Foo"),
        ],
        [],
    )

